// Promise.race：第一个 settled（落定，成功或失败）的成员决定整体结果
const promiseRace = (arr) =>
  new Promise((resolve, reject) => {
    // Promise.resolve：把普通值转成 Promise，.then 始终异步，与原生行为一致
    for (const p of arr) Promise.resolve(p).then(resolve, reject);
    // 任一先 resolve/reject 都会触发外层；后到的结果会被忽略（Promise 已不可逆）
  });

// Promise.all：全部 fulfilled 才 resolve；任一 reject 立刻 reject；空数组得 []
const promiseAll = (arr) =>
  new Promise((resolve, reject) => {
    const out = [];
    let n = arr.length;
    if (!n) return resolve(out); // 边界：无任务，直接成功
    arr.forEach((p, i) =>
      Promise.resolve(p).then(
        (v) => {
          out[i] = v; // 按下标回填，保证输出顺序与输入一致
          if (--n === 0) resolve(out); // 最后一项成功才整体 resolve
        },
        reject, // 第一个失败直通外层，后续结果不再关心
      ),
    );
  });

// allSettled：永不因单项失败而整体 reject；内部可复用 Promise.all + 每项包一层
const allSettled = (arr) =>
  Promise.all(
    arr.map((p) =>
      Promise.resolve(p).then(
        (value) => ({ status: 'fulfilled', value }), // 成功：规范规定的形状
        (reason) => ({ status: 'rejected', reason }), // 失败：吞掉 reject，转成结果对象
      ),
    ),
  );

// 全失败时的错误：有 AggregateError 则用规范类型，否则降级为 Error + errors 属性
const rejAll = (errors) =>
  typeof AggregateError !== 'undefined'
    ? new AggregateError(errors, 'All promises were rejected')
    : Object.assign(new Error('All promises were rejected'), { errors });

const promiseAny = (arr) =>
  new Promise((resolve, reject) => {
    const n = arr.length;
    if (!n) return reject(rejAll([])); // 空数组：立即全失败
    let left = n; // 剩余未 settled 的数量
    const errors = [];
    arr.forEach((p, i) =>
      Promise.resolve(p).then(resolve, (e) => {
        errors[i] = e; // 按下标存原因，与 allSettled 类似便于对齐原顺序
        if (!--left) reject(rejAll(errors)); // 最后一项也失败了才 reject
      }),
    );
  });

// 串行：for...of + await，循环体天然「等上一个 await 结束再下一次迭代」
const runSeries = async (tasks) => {
  const out = [];
  for (const t of tasks) {
    out.push(await t()); // await：暂停当前 async 函数，让出线程
  }
  return out;
};

// 重试：try/catch + 递归；attempts 表示「剩余机会」
const retry = async (fn, attempts = 3, delayMs = 0) => {
  try {
    return await fn();
  } catch (e) {
    if (attempts <= 1) throw e; // 机会用尽，原样抛出
    if (delayMs) await new Promise((r) => setTimeout(r, delayMs)); // 退避间隔
    return retry(fn, attempts - 1, delayMs); // 递归：减少一次剩余次数
  }
};

// 教学示意：仅 fulfilled；生产级需 A+ 规范（2.3 thenable 等）
class MyPromise {
  constructor(executor) {
    this._state = 'pending'; // 三态之一，本题只演示 fulfilled
    this._value = undefined; // 终值
    this._cb = []; // pending 时注册的 then 回调
    const resolve = (v) => {
      if (this._state !== 'pending') return; // 只能决议一次
      this._state = 'fulfilled';
      this._value = v;
      // queueMicrotask：then 回调须异步，避免与同步栈交错（简化版用微任务）
      queueMicrotask(() => this._cb.splice(0).forEach((fn) => fn()));
    };
    try {
      executor(resolve, () => {}); // 第二个参数应为 reject，此处占位
    } catch (e) {
      /* 同步抛错应走 reject，此处省略 */
    }
  }
  then(onFulfilled) {
    return new MyPromise((resolve) => {
      const run = () =>
        resolve(onFulfilled != null ? onFulfilled(this._value) : this._value); // 透传
      this._state === 'fulfilled'
        ? queueMicrotask(run) // 已决议：下一微任务执行
        : this._cb.push(run); // 未决议：先入队，resolve 时统一 flush
    });
  }
}

// Object.prototype.toString：依赖内部 [[Class]]，必须用 call 把 this 绑到待测值上
const getType = (x) => Object.prototype.toString.call(x);

// 若题面要 'array'：getType(x).slice(8, -1).toLowerCase()

// myCall：把「要调用的函数」临时挂到 ctx 上，使 this 指向 ctx
Function.prototype.myCall = function (ctx, ...args) {
  const o = ctx == null ? globalThis : Object(ctx); // null/undefined → 全局；原始值会装箱
  const k = Symbol('__fn__'); // 唯一键，降低与对象自有属性冲突概率
  o[k] = this; // 当前函数作为 o 的方法
  try {
    return o[k](...args); // 以方法形式调用，this === o
  } finally {
    delete o[k]; // 无论成功失败都清理临时属性
  }
};

// myApply：第二参为数组或类数组，统一转成数组后委托 myCall
Function.prototype.myApply = function (ctx, arr) {
  return this.myCall(ctx, ...Array.from(arr ?? []));
};

// myBind：闭包保存原函数 fn 与预设参数 a1
Function.prototype.myBind = function (ctx, ...a1) {
  const fn = this;
  const bound = function (...a2) {
    // new bound() 时 this 是实例，应走构造路径；否则用绑定的 ctx
    return fn.apply(this instanceof bound ? this : ctx, [...a1, ...a2]);
  };
  // 使 bound 实例能 instanceof 原构造函数：共享原型链
  bound.prototype = Object.create(fn.prototype);
  return bound;
};

// myNew：Ctor 为构造函数，args 为构造参数
const myNew = (Ctor, ...args) => {
  const o = Object.create(Ctor.prototype); // 实例原型链指向 Ctor.prototype
  const r = Ctor.apply(o, args); // 执行构造函数体，可能往 o 上挂属性
  // 规范：仅当返回值为对象或函数时用返回值，否则用 o
  return r != null && (typeof r === 'object' || typeof r === 'function') ? r : o;
};

// instanceof：沿 __proto__ 链查找是否等于 R.prototype
const myInstanceof = (L, R) => {
  const proto = R.prototype; // 右侧构造函数的 prototype 引用
  for (let o = Object.getPrototypeOf(L); o; o = Object.getPrototypeOf(o)) {
    if (o === proto) return true; // 链上某环与目标 prototype 相同
  }
  return false; // 查到 null 仍未命中
};

// assign：浅拷贝；后出现的同名属性覆盖先出现的
const assign = (target, ...srcs) => {
  const t = Object(target); // 与原生一致：包装原始类型为对象
  for (const s of srcs) {
    if (s == null) continue; // null / undefined 源直接跳过
    const obj = Object(s);
    for (const k of Object.keys(obj)) {
      // 仅遍历可枚举自有字符串键；Object.getOwnPropertySymbols 另题
      t[k] = obj[k];
    }
  }
  return t; // 返回同一引用 target
};

// Object.create：借助 new 把实例的 [[Prototype]] 设为 proto
const create = (proto) => {
  const F = function () {}; // 空构造函数，仅占位
  F.prototype = proto; // 实例将继承 proto 链上的属性
  return new F(); // new 出的对象 __proto__ === proto
};

// 子集 stringify：递归 + 分支；生产级需处理循环引用（WeakSet）等
const stringify = (v) => {
  if (v === null || typeof v === 'number' || typeof v === 'boolean') return String(v); // null 与原始类型
  if (typeof v === 'string') return JSON.stringify(v); // 自动加引号并转义
  if (Array.isArray(v)) return '[' + v.map(stringify).join(',') + ']'; // 数组元素递归
  return (
    '{' +
    Object.keys(v)
      .map((k) => JSON.stringify(k) + ':' + stringify(v[k])) // 键必须带引号
      .join(',') +
    '}'
  );
};

// 深比较：先 ===（含同一引用与多数原始值相等；NaN 需题面单独约定）
const isEqual = (a, b) => {
  if (a === b) return true; // 同一引用或严格相等（NaN 仍不相等）
  if (a == null || b == null || typeof a !== 'object' || typeof b !== 'object') return false;
  const ak = Object.keys(a),
    bk = Object.keys(b);
  if (ak.length !== bk.length) return false; // 可枚举键数量须一致
  return ak.every((k) => k in b && isEqual(a[k], b[k])); // 键名与子值都递归相等
};

// once：用闭包保存「是否已执行」与「首次结果」
const once = (fn) => {
  let done; // 真值表示已执行过
  let memo; // 缓存首次返回值
  return function (...a) {
    return done ? memo : ((done = 1), (memo = fn.apply(this, a))); // 逗号表达式：先置位再求值
  };
};

// memoize：Map 存「序列化参数 → 结果」
const memoize = (fn) => {
  const c = new Map();
  return function (...a) {
    const k = JSON.stringify(a); // 简单键；键冲突/顺序敏感是常见追问点
    if (c.has(k)) return c.get(k); // 命中缓存
    const v = fn.apply(this, a);
    c.set(k, v); // 写入缓存
    return v;
  };
};

// curry：fn.length 为形参个数；用 function 保留外层调用时的 this
const curry = (fn) =>
  function curried(...a) {
    // 已凑够参数：直接调用原函数
    if (a.length >= fn.length) return fn.apply(this, a);
    // 否则返回函数继续收参，并与已收集的 a 合并
    return (...b) => curried.apply(this, [...a, ...b]);
  };

// 链式累加示例：空调 () 返回累计和；非空调继续返回函数
function createAdder(sum = 0) {
  const add = (n) => {
    if (n === undefined) return sum; // add()：结束链，给出结果
    sum += n;
    return add; // add(1)(2) 继续返回同一累加器
  };
  return add;
}
// const add = createAdder(); add(1)(2)(3)() === 6

// compose：最右函数最先吃到 x，结果逐层向左传
const compose =
  (...fns) =>
  (x) =>
    fns.reduceRight((v, f) => f(v), x); // 初始累积值为 x

// pipe(...fns)(x) === fns.reduce((v, f) => f(v), x)

// debounce：每次触发重置定时器，只有停顿满 wait 才执行
const debounce = (fn, wait) => {
  let t; // 保存定时器 id
  return function (...args) {
    clearTimeout(t); // 新一轮输入，取消上一次「即将执行」
    t = setTimeout(() => fn.apply(this, args), wait); // 保留调用方 this 与参数
  };
};

// 时间戳节流：距上次执行满 wait 才再次执行，首调 prev=0 会立刻通过
const throttle = (fn, wait) => {
  let prev = 0;
  return function (...args) {
    const now = Date.now();
    if (now - prev >= wait) {
      prev = now; // 记录本次执行时刻
      fn.apply(this, args);
    }
  };
};

// 定时器闸门：一次执行后，在 wait 内 t 非空，直接 return
const throttleTimer = (fn, wait) => {
  let t;
  return function (...args) {
    if (t) return; // 仍在冷却期
    fn.apply(this, args); // 立即执行一次
    t = setTimeout(() => {
      t = null; // 冷却结束，允许下一次
    }, wait);
  };
};

// map：length 遍历 + `i in arr` 跳过 empty slot
const map = (arr, fn, ctx) => {
  const out = [];
  for (let i = 0; i < arr.length; i++) {
    if (i in arr) out[i] = fn.call(ctx, arr[i], i, arr); // 绑定 thisArg 并传入三元组
  }
  return out;
};

// uniqueBy：filter + Map；m.set 在 && 右侧仍会执行，用于「边记边滤」
const uniqueBy = (arr, key) => {
  const m = new Map();
  return arr.filter((o) => !m.has(o[key]) && m.set(o[key], true)); // 首次见到的 key 才保留
};

// flatten：仍数组且剩余深度 >0 则继续递归，否则包一层成叶子
const flatten = (arr, d = Infinity) =>
  arr.flatMap((v) =>
    Array.isArray(v) && d > 0 ? flatten(v, d - 1) : [v],
  );

// listToTree：Map 存 id→带 children 的节点；reduce 挂边
const listToTree = (list) => {
  const m = new Map(list.map((n) => [n.id, { ...n, children: [] }])); // 复制数据并初始化 children
  return list.reduce((roots, n) => {
    const node = m.get(n.id);
    const p = m.get(n.parentId); // 父不存在则视为根
    (p ? p.children : roots).push(node); // 有父挂子树，无父进 roots
    return roots;
  }, []);
};

// treeToList：DFS；解构把子节点从 rest 中剥离
const treeToList = (nodes, k = 'children') => {
  const out = [];
  const walk = (n) => {
    if (!n) return;
    const { [k]: ch, ...rest } = n; // rest 为不含 children 的浅拷贝字段
    out.push(rest);
    (ch ?? []).forEach(walk); // 递归子树
  };
  [].concat(nodes).forEach(walk); // 兼容单根或森林
  return out;
};

// JSON.parse(JSON.stringify)：简单但有类型与循环引用局限
// 递归 + WeakMap：在「图」上深拷贝，避免环导致栈溢出
const clone = (x, seen = new WeakMap()) => {
  if (x == null || typeof x !== 'object') return x; // 原始值或 null
  if (seen.has(x)) return seen.get(x); // 环：返回已建好的镜像
  if (Array.isArray(x)) {
    const a = [];
    seen.set(x, a); // 先登记，再递归填槽，处理自引用数组
    x.forEach((v, i) => (a[i] = clone(v, seen)));
    return a;
  }
  const o = {};
  seen.set(x, o);
  for (const k of Object.keys(x)) o[k] = clone(x[k], seen); // 仅自有可枚举字符串键
  return o;
};

// EventEmitter：Map<事件名, Set<回调>>
class EventEmitter {
  constructor() {
    this._m = new Map();
  }
  on(ev, fn) {
    const s = this._m.get(ev) ?? new Set(); // 无则新建监听集合
    s.add(fn);
    this._m.set(ev, s);
    return this; // 链式可选
  }
  off(ev, fn) {
    this._m.get(ev)?.delete(fn);
    return this;
  }
  emit(ev, ...args) {
    const s = this._m.get(ev);
    if (!s || !s.size) return false; // 无监听
    [...s].forEach((fn) => fn(...args)); // 快照：避免遍历时 Set 被改
    return true;
  }
}

// 冒泡：每轮末尾 i 位置固定为当前最大；swapped 优化已排序输入
const bubbleSort = (arr) => {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    let swapped = false;
    for (let j = 0; j < i; j++) {
      if (a[j] > a[j + 1]) {
        [a[j], a[j + 1]] = [a[j + 1], a[j]]; // 解构交换
        swapped = true;
      }
    }
    if (!swapped) break; // 已有序，提前退出
  }
  return a;
};

// 选择排序：每轮把「最小值」换到区间左端 i
const selectionSort = (arr) => {
  const a = [...arr];
  for (let i = 0; i < a.length; i++) {
    let min = i; // 假设 i 为最小
    for (let j = i + 1; j < a.length; j++) if (a[j] < a[min]) min = j; // 扫描更新最小下标
    if (min !== i) [a[i], a[min]] = [a[min], a[i]]; // 非平凡才交换
  }
  return a;
};

// 插入排序：把 a[i] 插入到左侧有序段正确位置
const insertionSort = (arr) => {
  const a = [...arr];
  for (let i = 1; i < a.length; i++) {
    const x = a[i]; // 待插入元素
    let j = i;
    while (j > 0 && a[j - 1] > x) {
      a[j] = a[j - 1]; // 大元素整体右移一格
      j--;
    }
    a[j] = x; // 空出的位置放入 x
  }
  return a;
};

// 三路快排（非原地）：好写；与 Lomuto/Hoare 原地 partition 不同
const quickSort = (arr) => {
  if (arr.length <= 1) return arr; // 递归基
  const p = arr[0]; // 基准；工程常随机化
  const left = [],
    mid = [],
    right = [];
  for (const x of arr) {
    if (x < p) left.push(x);
    else if (x > p) right.push(x);
    else mid.push(x); // 与 pivot 相等放中间，缓解全相等退化
  }
  return [...quickSort(left), ...mid, ...quickSort(right)];
};

// 默认 sort：按字符串排，[10, 2, 1].sort() 会得到 [1, 10, 2]
// 数值升序：(a, b) => a - b；返回值符号决定顺序，0 表示相等
// 原地排序：先 [...arr] 再 sort 可避免副作用
const sortAsc = (arr) => [...arr].sort((a, b) => a - b);

// 对象数组：users.sort((a, b) => a.age - b.age)
// 稳定性：ES2019 起 sort 规范为稳定排序；极老引擎以实际为准
